import os, re; p=os.path.expanduser('~/caeron-gateway/injection.py'); c=open(p).read(); c=re.sub(r"tag = 'monthly'.*?ASC", "tag = 'monthly' AND is_active = 1 ORDER BY created_at DESC LIMIT 2", c); c=re.sub(r"tag = 'weekly'.*?ASC", "tag = 'weekly' AND is_active = 1 ORDER BY created_at DESC LIMIT 1", c); c=re.sub(r"tag = 'round_rollup'.*?ASC", "tag = 'round_rollup' AND is_active = 1 AND date(created_at) = ? ORDER BY created_at DESC LIMIT 8", c, flags=re.DOTALL); open(p,'w').write(c)